import { ANSWERS } from "./answers.js";

// Comprehensive valid guess dictionaries.
// Source: ENABLE word list (standard game dictionary) + curated additions.
// Packed as concatenated strings for compact bundle size, unpacked to Sets at load.

function unpack(s, len) {
  const set = new Set();
  for (let i = 0; i < s.length; i += len) set.add(s.substring(i, i + len));
  return set;
}

const W4 = "";

const W5 = "";

const W6 = "";

const W7 = "";

export const VALID_GUESSES = {
  4: unpack(W4, 4),
  5: unpack(W5, 5),
  6: unpack(W6, 6),
  7: unpack(W7, 7),
};

// Ensure all answer words are valid guesses
for (const [len, words] of Object.entries(ANSWERS)) {
  const dict = VALID_GUESSES[len];
  if (dict) words.forEach(w => dict.add(w));
}
